function solve(nums) {
    const N = nums.length;

    if (N < 3) {
        return 0;
    }

    /**
     * Calculates the minimum cost to make all indices in S special, 
     * assuming neighbors not in S are left untouched (i.e., kept at their original value).
     * @param {number[]} S - Array of target peak indices.
     * @returns {number} The total cost.
     */
    const calculateCost = (S) => {
        let totalCost = 0;
        for (const i of S) {
            // i is guaranteed to be in [1, N-2]

            const leftNeighbor = nums[i - 1];
            const rightNeighbor = nums[i + 1];

            // Required value for nums'[i] must be strictly greater than both neighbors.
            // R_i = max(nums[i-1], nums[i+1]) + 1
            const requiredValue = Math.max(leftNeighbor, rightNeighbor) + 1;

            const currentValue = nums[i];

            // Cost is max(0, Required - Current)
            if (requiredValue > currentValue) {
                const cost = requiredValue - currentValue;
                totalCost += cost;
            }
        }
        return totalCost;
    };

    // 1. Determine Candidate Set S1 (Indices 1, 3, 5, ...)
    const S1 = [];
    for (let i = 1; i <= N - 2; i += 2) {
        S1.push(i);
    }

    // 2. Determine Candidate Set S2 (Indices 2, 4, 6, ...)
    const S2 = [];
    for (let i = 2; i <= N - 2; i += 2) {
        S2.push(i);
    }

    // 3. Calculate costs for both optimal patterns
    let cost1 = calculateCost(S1);
    let cost2 = calculateCost(S2);

    // 4. Return the minimum cost
    return Math.min(cost1, cost2);
}

